void update_time_simple_360(int second, int minute, int hour, bool mode, bool am, int day, int month, int year, int weekday)
{
#ifdef ENABLE_FACE_SIMPLE_360
    if (!face_simple_360)
    {
        return;
    }
	lv_img_set_src(face_simple_360_28_141970, face_simple_360_dial_img_28_141970_group[((weekday + 6) / 1) % 7]);
	lv_img_set_src(face_simple_360_29_151518, face_simple_360_dial_img_29_151518_group[(minute / 1) % 10]);
	lv_img_set_src(face_simple_360_30_151518, face_simple_360_dial_img_29_151518_group[(minute / 10) % 10]);
	lv_img_set_src(face_simple_360_31_151518, face_simple_360_dial_img_29_151518_group[(hour / 1) % 10]);
	lv_img_set_src(face_simple_360_32_151518, face_simple_360_dial_img_29_151518_group[(hour / 10) % 10]);
	lv_img_set_src(face_simple_360_33_140742, face_simple_360_dial_img_33_140742_group[(day / 1) % 10]);
	lv_img_set_src(face_simple_360_34_140742, face_simple_360_dial_img_33_140742_group[(day / 10) % 10]);
	lv_img_set_src(face_simple_360_35_140742, face_simple_360_dial_img_33_140742_group[(month / 1) % 10]);
	lv_img_set_src(face_simple_360_36_140742, face_simple_360_dial_img_33_140742_group[(month / 10) % 10]);

#endif
}

