void update_status_simple_360(int battery, bool connection){
#ifdef ENABLE_FACE_SIMPLE_360
    if (!face_simple_360)
    {
        return;
    }
	lv_img_set_src(face_simple_360_23_147294, face_simple_360_dial_img_23_147294_group[(battery / 1) % 10]);
	lv_img_set_src(face_simple_360_24_147294, face_simple_360_dial_img_23_147294_group[(battery / 10) % 10]);
	lv_img_set_src(face_simple_360_25_147294, face_simple_360_dial_img_23_147294_group[(battery / 100) % 10]);
	if (battery < 100)
	{
		lv_obj_add_flag(face_simple_360_25_147294, LV_OBJ_FLAG_HIDDEN);
	} else {
		lv_obj_clear_flag(face_simple_360_25_147294, LV_OBJ_FLAG_HIDDEN);
	}

#endif
}

