void update_all_simple_360(int second, int minute, int hour, bool mode, bool am, int day, int month, int year, int weekday, 
    int temp, int icon, int battery, bool connection, int steps, int distance, int kcal, int bpm, int oxygen)
{
#ifdef ENABLE_FACE_SIMPLE_360
    update_time_simple_360(second, minute, hour, mode, am, day, month, year, weekday);
    update_weather_simple_360(temp, icon);
    update_status_simple_360(battery, connection);
    update_activity_simple_360(steps, distance, kcal);
    update_health_simple_360(bpm, oxygen);
#endif
}

void update_check_simple_360(lv_obj_t *root, int second, int minute, int hour, bool mode, bool am, int day, int month, int year, int weekday, 
    int temp, int icon, int battery, bool connection, int steps, int distance, int kcal, int bpm, int oxygen)
{
#ifdef ENABLE_FACE_SIMPLE_360
    if (root != face_simple_360)
    {
        return;
    }
    update_time_simple_360(second, minute, hour, mode, am, day, month, year, weekday);
    update_weather_simple_360(temp, icon);
    update_status_simple_360(battery, connection);
    update_activity_simple_360(steps, distance, kcal);
    update_health_simple_360(bpm, oxygen);
#endif
}


